import assert from "node:assert/strict";

const rows = [];

for (let i = 0; i < 750_000; i += 1) {
  rows.push({
    id: i,
    label: `row-${i.toString(36).padStart(6, "0")}`,
    active: (i & 1) === 0
  });
}

assert.equal(rows.length, 750_000);

const fs = require("node:fs");
const path = require("node:path");

const target = path.join(__dirname, "payload.txt");
const descriptors = [];

for (let i = 0; i < 256; i += 1) {
  descriptors.push(fs.openSync(target, "r"));
}

for (const fd of descriptors) {
  fs.closeSync(fd);
}

console.log(`opened ${descriptors.length} descriptors`);

